member.example:
Bind the LocalizeStringEvent localization entry to a string ViewModel property using a serialized binder field — the target LocalizeStringEvent is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private LocalizeStringEventEntryBinder _label;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public string _label; // bound value is used as the table entry key
    }


Bind the LocalizeStringEvent localization entry to a string ViewModel property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private LocalizeStringEvent _target;
        
        private LocalizeStringEventEntryBinder Label =>
            new(_target);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public string _label;
    }

Switch the LocalizeStringEvent localization entry between two keys using a serialized binder field — the target LocalizeStringEvent is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private LocalizeStringEventEntrySwitcherBinder _isActive;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isActive;
    }


Switch the LocalizeStringEvent localization entry between two keys by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private LocalizeStringEvent _target;
        
        private LocalizeStringEventEntrySwitcherBinder IsActive => new(
            _target, trueValue: "ui_active_key", falseValue: "ui_inactive_key");
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isActive;
    }
